arguments.command:
# Get dynamic symbols sorted by address, then resolve the monosgen addresses
# Addresses: 0x222098, 0x222234, 0x19bac0, 0x19bc14
aarch64-linux-gnu-nm -D --defined-only /tmp/symbols/libmonosgen-2.0.so | sort | awk '
BEGIN {
    split("0x222098 0x222234 0x19bac0 0x19bc14", targets, " ")
    for (i in targets) { target_addrs[i] = strtonum(targets[i]) }
    n = length(targets)
}
{
    addr = strtonum("0x" $1)
    name = $3
    if (prev_addr > 0) {
        for (i = 1; i <= n; i++) {
            if (target_addrs[i] >= prev_addr && target_addrs[i] < addr && !found[i]) {
                printf "0x%x -> %s+0x%x\n", target_addrs[i], prev_name, target_addrs[i] - prev_addr
                found[i] = 1
            }
        }
    }
    prev_addr = addr
    prev_name = name
}
END {
    for (i = 1; i <= n; i++) {
        if (!found[i] && target_addrs[i] >= prev_addr) {
            printf "0x%x -> %s+0x%x\n", target_addrs[i], prev_name, target_addrs[i] - prev_addr
        }
    }
}
'

